			Owner savedOwner = invocation.getArgument(0);
			Pet savedPet = savedOwner.getPets().get(0);
			savedPet.setId(1);
			return savedOwner;
		});

		// when
		mockMvc
			.perform(post("/api/owners/1/pets").contentType(MediaType.APPLICATION_JSON)
